SELECT COUNT(DISTINCT S.PK_SIAPE) AS QTD FROM SERVIDOR S JOIN CALC_HORA_AULA_MEDIA C ON C.SIAPE = S.PK_SIAPE WHERE C.ANO = 2020 AND C.SEMESTRE = 1 AND C.SIGLA_CAMPUS = 'LUZ' AND LOWER(S.CONTRATO) = LOWER('efetivos') AND (LOWER(S.AREA_INGRESSO) LIKE LOWER('%ciencia da computacao%') OR LOWER(S.AREA_INGRESSO) LIKE LOWER('%ciencia da computacao%'))